var CUSTOM_SVG_SYMBOLS = d3_map();

function setSVGsymbol(type, path){
    CUSTOM_SVG_SYMBOLS.set(type, path);
}
Registry.setComponent('svg.setSymbolPath', setSVGsymbol);

export function getSVGsymbol(type) {
    /*
     * Default arguments
     * 0 - size | width
     * 1 - height
     * 2 - border radius
     */
    return function(size, size1, custom, side) {
        if (LOCATION_MARKERS.has(type)) {
            return Registry.getComponent('svg.symbolPath.geo')(type, size, side);
        }
        var customShape = CUSTOM_SVG_SYMBOLS.get(type);
        if(customShape){
            return invokeFunction(customShape, size);
        }
        switch (type) {
            case 'asterisk':
                return `M0 0 C${size * -0.25} ${size * -0.65} ${size * 0.25} ${size * -0.65} 0 0 C${size * 0.5} ${size * -0.633} ${size *
                    0.65} ${size * -0.117} 0 0 C${size * 0.583} ${size * 0.083} ${size * 0.583} ${size * 0.65} 0 0 C${size * 0.25} ${size *
                    0.65} ${size * -0.25} ${size * 0.65} 0 0 C${size * -0.617} ${size * 0.65} ${size * -0.55} ${size * 0.017} 0 0 C${size *
                    -0.483} ${size * -0.05} ${size * -0.583} ${size * -0.717} 0 0 Z`;
            case 'bean':
                return `M0 ${size * 0.5} A${size * 0.25} ${size * 0.5} 0 0 1 0 ${-size * 0.5} A${size * 0.15} ${size *
                    0.25} 0 0 1 1 0 A${size * 0.15} ${size * 0.25} 0 0 1 0 ${size * 0.5}`;
            case 'butterfly':
                return `M0 ${-size * 0.25} C0 ${-size * 0.25} ${size * 0.85} ${-size} ${size * 0.3} ${size * 0.25} C${size * 0.6} ${size *
                    0.7} 0 ${size * 0.4} 0 ${size * 0.4} M0 ${-size * 0.25} C0 ${-size * 0.25} ${-size * 0.85} ${-size} ${-size *
                    0.3} ${size * 0.25} C${-size * 0.6} ${size * 0.7} 0 ${size * 0.4} 0 ${size * 0.4} M0 ${-size * 0.25} L${size *
                    0.1} ${-size * 0.5} M0 ${-size * 0.25} L${-size * 0.1} ${-size * 0.5}`;
            case 'clover':
                return `M${size * 0.033} ${size * -0.033} C${size * -0.133} ${size * -0.966} ${size * 1.066} ${size * -0.116} ${size *
                    0.1} ${size * 0.033} C${size * 0.933} ${size * 0.233} ${size * -0.133} ${size * 0.9} ${size * 0.016} ${size *
                    0.083} C${size * -0.633} ${size * 0.6} ${size * -0.6} ${size * -0.6} ${size * 0.033} ${size * -0.033} Z`;
            case 'cloverFour':
                return `M${-size * 0.05} ${-size * 0.05} C${-size * 0.4} ${-size * 0.6} ${size * 0.4} ${-size * 0.6} ${size *
                    0.05} ${-size * 0.05} C${size * 0.6} ${-size * 0.4} ${size * 0.6} ${size * 0.4} ${size * 0.05} ${size * 0.05} C${size *
                    0.4} ${size * 0.6} ${-size * 0.4} ${size * 0.6} ${-size * 0.05} ${size * 0.05} C${-size * 0.6} ${size * 0.4} ${-size *
                    0.6} ${-size * 0.4} ${-size * 0.05} ${-size * 0.05} Z`;
            case 'cross':
                return `M${-size / 2} ${-size * 0.2} L${-size * 0.2} ${-size * 0.2} L${-size * 0.2} ${-size / 2} L${size * 0.2} ${-size /
                    2} L${size * 0.2} ${-size * 0.2} L${size / 2} ${-size * 0.2} L${size / 2} ${size * 0.2} L${size * 0.2} ${size *
                    0.2} L${size * 0.2} ${size / 2} L${-size * 0.2} ${size / 2} L${-size * 0.2} ${size * 0.2} L${-size / 2} ${size *
                    0.2} Z`;
            case 'diamond':
                return `M${-size * 0.4} 0 L0 ${-size / 2} L${size * 0.4} 0 L0 ${size / 2} Z`;
            case 'ellipse':
                return `M${-size * 0.5} 0 A${size * 0.5} ${size * 0.35} 0 0 1 ${size * 0.5} 0 A${size * 0.5} ${size * 0.35} 0 0 1 ${-size *
                    0.5} 0`;
            case 'gear':
                return `M${size * -0.088} ${size * -0.365} L${size * -0.084} ${size * -0.471} L${size * 0.092} ${size * -0.471} L${size *
                    0.097} ${size * -0.369} L${size * 0.194} ${size * -0.317} L${size * 0.27} ${size * -0.386} L${size * 0.409} ${size *
                    -0.263} L${size * 0.339} ${size * -0.189} L${size * 0.364} ${size * -0.088} L${size * 0.478} ${size * -0.088} L${size *
                    0.478} ${size * 0.097} L${size * 0.369} ${size * 0.097} L${size * 0.325} ${size * 0.192} L${size * 0.394} ${size *
                    0.265} L${size * 0.254} ${size * 0.396} L${size * 0.197} ${size * 0.325} L${size * 0.092} ${size * 0.364} L${size *
                    0.092} ${size * 0.476} L${size * -0.084} ${size * 0.476} L${size * -0.084} ${size * 0.364} L${size * -0.185} ${size *
                    0.32} L${size * -0.263} ${size * 0.394} L${size * -0.388} ${size * 0.26} L${size * -0.317} ${size * 0.192} L${size *
                    -0.354} ${size * 0.097} L${size * -0.473} ${size * 0.097} L${size * -0.473} ${size * -0.091} L${size * -0.356} ${size *
                    -0.091} L${size * -0.317} ${size * -0.189} L${size * -0.384} ${size * -0.258} L${size * -0.267} ${size *
                    -0.384} L${size * -0.184} ${size * -0.312} L${size * -0.088} ${size * -0.365} Z`;
            case 'heart':
                return `M0 ${-size * 0.2} C${size * 0.65} ${-size * 0.65} ${size * 0.65} ${size * 0.2} 0 ${size * 0.45} C${-size *
                    0.65} ${size * 0.2} ${-size * 0.65} ${-size * 0.65} 0 ${-size * 0.2}Z`;
            case 'star':
                return `M0 ${-size * 0.5} L${size * 0.122} ${-size * 0.12} L${size * 0.5} ${-size * 0.12} L${size * 0.197} ${size *
                    0.12} L${size * 0.306} ${size * 0.5} L0 ${size * 0.274} L${-size * 0.306} ${size * 0.5} L${-size * 0.197} ${size *
                    0.12} L${-size * 0.5} ${-size * 0.12} L${-size * 0.122} ${-size * 0.12} Z`;
            case 'malteseCross':
                return `M${-size * 0.3} ${-size * 0.4} A${size * 0.3} ${size * 0.1} 0 0 1 ${size * 0.3} ${-size * 0.4} L${size *
                    0.2} ${-size * 0.2} L${size * 0.4} ${-size * 0.3} A${size * 0.1} ${size * 0.3} 0 0 1 ${size * 0.4} ${size *
                    0.3} L${size * 0.2} ${size * 0.2} L${size * 0.3} ${size * 0.4} A${size * 0.3} ${size * 0.1} 0 0 1 ${-size *
                    0.3} ${size * 0.4} L${-size * 0.2} ${size * 0.2} L${-size * 0.4} ${size * 0.3} A${size * 0.1} ${size *
                    0.3} 0 0 1 ${-size * 0.4} ${-size * 0.3} L${-size * 0.2} ${-size * 0.2} Z`;
            case 'square':
                var side = +arguments[0],
                    r = +pick(arguments[2], 0);

                if (defined(arguments[2])) {
                    return roundedRect(-side / 2, -side / 2, side, side, getBorderRadius(r));
                } else {
                    return `M${-size * 0.5} ${-size * 0.5} L${size * 0.5} ${-size * 0.5} ${size * 0.5} ${size * 0.5} ${-size * 0.5} ${size *
                        0.5} Z`;
                }

            case 'triangle-up':
                return `M${-size * 0.5} ${size * 0.285} L0 ${-size * 0.43} ${size * 0.5} ${size * 0.285} Z`;
            case 'triangle-down':
                return `M0 ${size * 0.43} L${-size * 0.5} ${-size * 0.285} L${size * 0.5} ${-size * 0.285} Z`;
            case 'triangle-right':
                return `M${-size * 0.5} ${-size * 0.43} L${size * 0.285} 0 L${-size * 0.5} ${size * 0.43} Z`;
            case 'triangle-left':
                return `M${size * 0.5} ${size * 0.43} L${-size * 0.285} 0 L${size * 0.5} ${-size * 0.43} Z`;
            case 'arrow':
                return `M${-size * 0.5} ${size * 0.2} L0 ${-size * 0.5} ${size * 0.5} ${size * 0.2} ${size * 0.25} ${size * 0.2} ${size *
                    0.25} ${size * 0.5} ${-size * 0.25} ${size * 0.5} ${-size * 0.25} ${size * 0.2} Z`;
            case 'rocket':
                return `M${-size * 0.5} ${size * 0.5} L0 ${-size * 0.5} ${size * 0.5} ${size * 0.5} 0 ${size * 0.25} ${-size * 0.5} ${size *
                    0.5} Z`;
            case 'nylon':
                return `M${-size / 2} ${-size / 4} L${-size / 4} ${-size / 4} L${-size / 4} ${-size / 2} M${-size / 4} 0 L${-size /
                    4} ${size / 4} L0 ${size / 4} M0 ${-size / 4} L${size / 4} ${-size / 4} L${size / 4} 0 M${size / 4} ${size /
                    2} L${size / 4} ${size / 4} L${size / 2} ${size / 4}`;
            case 'waves':
                return `M${-size} 0 C${(-size * 7) / 8} ${-size / 4} ${(-size * 5) / 8} ${-size / 4} ${-size / 2} 0 C${(-size * 3) /
                    8} ${-size / 4} ${-size / 8} ${-size / 4} 0 0 C${size / 8} ${size / 4} ${(size * 3) / 8} ${size / 4} ${size /
                    2} 0 C${(size * 5) / 8} ${-size / 4} ${(size * 7) / 8} ${-size / 4} ${(size * 3) / 4} 0`;
            case 'woven':
                return `M${-size / 4} ${-size / 4} L${size / 4} ${size / 4} M${size / 4} ${-size / 4} L${size / 2} ${-size / 2} M${-size /
                    4} ${size / 4} L${-size / 2} ${size / 2} M${size / 4} ${(size * 3) / 4} L${(size * 3) / 4} ${size / 4}`;
            case 'crosses':
                return `M ${-size / 4} ${-size / 4} L${size / 4},${size / 4} M${-size / 4},${size / 4} L${size / 4},${-size / 4}`;
            case 'caps':
                return `M${-size / 4} ${size / 4} L0 ${-size / 4} ${size / 4} ${size / 4}`;
            case 'hexagons':
                return `M${-size / 2} 0 L${-size / 4} 0 M${size / 2} 0 L${size / 4} ${-size / 2} L0 ${-size / 2} L${-size / 4} 0 L0 ${size /
                    2} L${size / 4} ${size / 2}Z`;
            case 'line':
            case 'horizontal-line':
                return `M${-size * 0.5} 0 L${size * 0.5} 0`;
            case 'diagonal-line-right':
                return `M${(-size * 3) / 4} ${-size / 4} L${-size / 4} ${(-size * 3) / 4} M${-size / 2} ${size / 2} L${size / 2} ${-size /
                    2} M${size / 4} ${(size * 3) / 4} L${(size * 3) / 4} ${size / 4}`;
            case 'vertical-line':
                return `M0 ${-size / 2} L0 ${size / 2}`;
            case 'vertical-line-z':
                return `M0 0 L0 ${size}`;
            case 'hexagon':
                return `M${size * 0.433} ${size * 0.25} L${0 * size} ${size * 0.5} L${size * -0.433} ${size * 0.25} L${size *
                    -0.433} ${size * -0.26} L${0 * size} ${size * -0.5} L${size * 0.433} ${size * -0.26} Z`;
            case 'diagonal-line-left':
                return `M${(-size * 3) / 4} ${size / 4} L${-size / 4} ${(size * 3) / 4} M${-size / 2} ${-size / 2} L${size / 2} ${size /
                    2} M${size / 4} ${(-size * 3) / 4} L${(size * 3) / 4} ${-size / 4}`;
            case 'oval':
                return `M${-size / 2} 0 A${size / 2} ${size / 2} 0 0 1 0 ${-size / 2} A${size / 2} ${size / 2} 0 0 1 ${-size / 2} 0`;
            case 'rect':
                var w = +arguments[0],
                    h = +pick(arguments[1], 0),
                    r = +pick(arguments[2], 0);

                if (defined(arguments[2])) {
                    return roundedRect(-w / 2, -h / 2, w, h, getBorderRadius(r));
                } else {
                    return `M${-w / 2} ${-h / 2} L${w / 2} ${-h / 2} L${w / 2} ${h / 2} L${-w / 2} ${h / 2}Z`;
                }

            case 'ninja':
                return `M${size * -0.267} ${size * -0.367} L${size * 0.167} ${size * -0.133} L${size * 0.433} ${size * -0.267} L${size *
                    0.2} ${size * 0.167} L${size * 0.333} ${size * 0.433} L${size * -0.1} ${size * 0.167} L${size * -0.367} ${size *
                    0.333} L${size * -0.167} ${size * -0.1} Z`;
            case 'whiskers':
                return whiskers([
                    ['line', size],
                    [custom.symbol, custom.size]
                ]);
            case 'whisker':
                return whiskerDouble(arguments[0], pick(arguments[1], 8), false);
            case 'horizontal-whisker':
                return whiskerDouble(pick(arguments[0], 8), arguments[1], true);
            case 'half-circle':
                return `M${-size / 2} ${size / 4} A${size / 2} ${size / 2} 0 0 1 ${size / 2} ${size / 4} Z`;
            case 'arrow-line':
                return `M${-size * 0.5} 0 L${size * 0.25} 0 M${size * 0.25} ${-size * 0.25} L${size * 0.5} 0 L${size * 0.25} ${size *
                    0.25}`;
            default:
                //circle
                return `M${-size / 2} 0 A${size / 2} ${size / 2} 0 0 1 ${size / 2} 0 A${size / 2} ${size / 2} 0 0 1 ${-size / 2} 0`;
        }
    };
}
Registry.setComponent('svg.symbolPath', getSVGsymbol);

export function addSVGmarker(parentElement, id, config, extraParams, chartObj) {
    let DIM = 10,
        { transform, rotate, color, symbolSize = { outer: 1, inner: 0.5 } } = extraParams,
        _position = transform ? { x: transform[0], y: transform[1], angle: rotate } : {},
        shape = config.symbol || extraParams.symbol,
        hasImage = config.imageUrl != null && config.imageUrl !== '',
        size = pick(config.size, pick(extraParams.strokeWidth, 1)),
        outersize = size * symbolSize.outer,
        innersize = size * symbolSize.inner,
        imgSize = (id != null ? size : outersize) * pick(extraParams.imageSize, DIM),
        /**
         *
         * removing inner marker if
         * 1. defined image marker or
         * 2. innerStrokeWidth is 0 and if it is not visible.
         */
        innerFillColor = config.innerFillColor || color,
        innerData =
            hasImage || (config.innerStrokeWidth === 0 && (config.innerFillOpacity === 0 || innerFillColor === 'transparent')) ? [] : [1],
        outerMarkSize = [hasImage ? imgSize : outersize * DIM, extraParams.size2d, extraParams.custom],
        innerMarkSize = [innersize * DIM, extraParams.size2d, extraParams.custom, 'inner'],
        marker;

    if (id != null) {
        //if id is not null create marker element else create path/image element
        let markerMark = Mark('marker', '#' + id);
        setPropVal(markerMark, 'properties.attrs', markerAttrs(size * DIM));
        marker = renderDom(markerMark, chartObj.getPatternSvg().select('defs'));
        // marker = markerMark.element;
    } else {
        marker = parentElement;
    }

    var isUpdate = marker.selectAll('path.outer').nodes().length; //No need to add animation for redraw

    //TODO: check 'stroke-width': (config.outerStrokeWidth || 0).toString()
    let outerMark = MarkerParser({
            prefix: 'outer',
            selection: '.outer',
            config: { ..._position, ...config, shape, color, size: outerMarkSize },
            context: chartObj.getPatternSvg(),
            defsPath: chartObj.defsLocation
        }),
        innerMark = MarkerParser({
            prefix: 'inner',
            selection: '.inner',
            data: innerData,
            config: { ..._position, ...config, shape, color, size: innerMarkSize }
        });

    let outerMark_ele = renderDom(outerMark, marker),
        innerMark_ele = renderDom(innerMark, marker);
    outerMark_ele.style('stroke-width', (config.outerStrokeWidth || 0).toString());

    // Animation
    let outermarkerpath = outerMark_ele,
        animationOptions = config.animation;

    if (!isUpdate && animationOptions && animationOptions.enabled) {
        //Implemented only for boxplot markers
        outermarkerpath
            .styles({
                'stroke-opacity': 0,
                'fill-opacity': 0
            })
            .transition()
            .delay(animationOptions.duration)
            .duration(animationOptions.duration)
            .styles({
                'stroke-opacity': config.outerStrokeOpacity
            });
    }
    return marker;
}
Registry.setComponent('svgRenderer.marker', addSVGmarker);

function markerAttrs(size) {
    return {
        orient: 0,
        viewBox: `${-size / 2} ${-size / 2} ${size} ${size}`,
        markerUnits: 'userSpaceOnUse',
        markerWidth: size,
        markerHeight: size
    };
}

export function getMarkerSize(chart) {
    // For area, line, scatter charts - if marker is enabled, the top markers will be clipped.
    // To avoid this, calculate the marker size and increase the clip area
    var DIM = { left: 0, top: 0, right: 0, bottom: 0 },
        behaviours = (chart.behaviouralEvents && chart.behaviouralEvents.eventManager.behaviours) || {};

    if (!chart.isAxisCategory || behaviours.PLOT_ZOOM || behaviours.PLOT_BRUSH || behaviours.CHART_SCROLL) {
        return DIM;
    }
    // If minrange and maxrange of the axes is specified, don't consider the marker size
    var xaxis = chart.systemConf.chart.axes.xaxis,
        yaxes = chart.systemConf.chart.axes.yaxis;
    var cXmin = xaxis.minRange != null && xaxis.minRange !== '',
        cXmax = xaxis.maxRange != null && xaxis.maxRange !== '',
        cYmin = yaxes.some(function(d) {
            return d.minRange != null && d.minRange !== '';
        }),
        cYmax = yaxes.some(function(d) {
            return d.maxRange != null && d.maxRange !== '';
        });
    if (cXmin && cXmax && cYmin && cYmax) {
        return DIM;
    }
    var rotated = chart.axes.rotated;

    var ms = d3_max(getMarkerSizes(chart)) / 2;
    return {
        left: (rotated ? cYmin : cXmin) ? DIM.left : ms,
        top: (rotated ? cXmax : cYmax) ? DIM.top : ms,
        right: (rotated ? cYmax : cXmax) ? DIM.right : ms,
        bottom: (rotated ? cXmin : cYmin) ? DIM.bottom : ms
    };
}

export function getMarkerSizes(chart) {
    let commonPlotoptions = chart.systemConf.chart.plot.plotoptions,
        canvasarea = chart.canvasarea;
    return chart.seriesdata.map(function(d, i) {
        var plotoptions = d.plotoptions,
            markerSize = 0,
            cName = chart.chartTypes[i].name;
        var gvp = utils.getValueOfPlotOptions(plotoptions ? plotoptions.marker : null, commonPlotoptions[cName].marker);
        if (
            /(area|arearange|line)/.test(cName) &&
            gvp('enabled') &&
            datacount_based_intelligence(chart, 'marker') &&
            dimension_based_intelligence(chart, 'marker', mathMin(canvasarea.width, canvasarea.height))
        ) {
            var size = gvp('size');
            markerSize = validateNullVal(
                size,
                validateNullVal(plotoptions ? plotoptions.strokeWidth : commonPlotoptions[cName].strokeWidth, 1)
            );
        } else if (cName === SCATTER_CHARTNAME) {
            markerSize = validateNullVal(gvp('size'), 2);
        }
        return markerSize * 10;
    });
}

export function blinkSVGsymbols(ele, blinkConf, chartObj) {
    if ($Browser.IE && blinkConf.enabled) {
        //Doesn't support css transforms on SVG element
        blinkSVGsymbolsByD3(ele, blinkConf); //Have to work
        return;
    }

    var defaultstyles = {
        animation: NULL,
        opacity: NULL,
        transform: NULL
    };
    if (!blinkConf.enabled) {
        ele.styles(defaultstyles);
        return;
    }

    var repeat = defined(blinkConf.repeat) ? blinkConf.repeat : 'infinite',
        type = blinkConf.type || 'twinkle',
        duration = (blinkConf.duration || 800) / 1000,
        delay = (type === 'fade' ? 250 : 0) / 1000,
        easingType = blinkConf.easingType || 'linear',
        parentContainer = d3_select(getRootBody(chartObj.container.node())).selectAll('div.__baseZC_Container__'),
        styleEle = appendEle(parentContainer, 'style', [1]),
        styleNode = styleEle.node(),
        keyFrame = '',
        animationID = `ZC${generateIdByPropValue(blinkConf, 'blink')}`;

    switch (type) {
        case 'twinkle':
            keyFrame =
                `${'\n@' + 'keyframes '}${animationID} { ` +
                `0% {transform: scale(1);}` +
                `50% {transform: scale(0);}` +
                `100% {transform: scale(1);} }\n`;
            break;
        case 'fade':
            keyFrame =
                `${'\n@' + 'keyframes '}${animationID} { ` +
                `0% {transform: scale(0);opacity: 1;}` +
                `100% {transform: scale(1);opacity: 0;} }\n`;
            ele.styles({
                transform: 'scale(0)',
                opacity: 1
            });
            break;
    }
    var documentIndex = getDocumentIndex(chartObj.container.node()),
        EFFECTS_STORE = DOCUMENT_OBJECT_HOLDER[documentIndex].ANIMATION;
    if (!(EFFECTS_STORE && defined(EFFECTS_STORE[animationID]))) {
        styleNode.innerHTML += keyFrame;
        EFFECTS_STORE[animationID] = true;
    }

    ele.style('animation', `${animationID} ${duration}s ${easingType} ${delay}s ${repeat}`).on('animationend', function() {
        d3_select(this).styles(defaultstyles);
    });
}

function blinkSVGsymbolsByD3(ele, blinkConf, repeat) {
    var count = defined(repeat) ? repeat - 1 : blinkConf.repeat || Infinity;
    if (!ele.node() || !count) {
        ele.styles({
            transform: null,
            opacity: null
        });
        return;
    }
    var isFade = (blinkConf.type || 'twinkle') === FADE_ANIMATION;
    var dur = (blinkConf.duration || 800) / 2,
        ease = d3_ease(blinkConf.easingType);
    var dur1 = dur,
        del1 = isFade ? 500 : 0,
        dur2 = isFade ? 0 : dur,
        start = isFade
            ? {
                  transform: 'scale(1)',
                  opacity: 0
              }
            : {
                  transform: 'scale(0)'
              },
        end = isFade
            ? {
                  transform: 'scale(0)',
                  opacity: 1
              }
            : {
                  transform: 'scale(1)'
              };
    ele.transition(); //Stop all the transitions. This will help to switch the blink type.
    ele.attrs(end)
        .transition()
        .delay(del1)
        .duration(dur1)
        .ease(ease)
        .attrs(start)
        .transition()
        .duration(dur2)
        .ease(ease)
        .attrs(end)
        .on('end', function() {
            blinkSVGsymbols(ele, blinkConf, count);
        });
}

export function getSegmentsForSymbol(type, size, x, y, h, rotated) {
    let start, end;
    switch (type) {
        case 'line':
            start = [x - size * 0.5, y];
            end = [x + size * 0.5, y];
            return [start, end];
        case `vertical-line`:
            start = [x, y - size * 0.5];
            end = [x, y + size * 0.5];
            return [start, end];
        case `horizontal-whisker`:
            return getSegmentsForWhisker(size, x, y, h, rotated);
        case `whisker`:
            return getSegmentsForWhisker(size, x, y, h);
    }
}

//!Note: Migrated from legend-colorbox.js due for custom bundling issue fix - getHTML4SVGSymbol and getSVGSymbolString functions
/**
 * Function that takes configuration of the symbol as parameter.
 * @param {Object} symbolConfig
 * @param {number} symbolConfig.size - size of the symbol/shape.
 * @param {string} symbolConfig.shape - shape of the object
 * @param {number} symbolConfig.width 
 * @param {number} symbolConfig.height
 * @param {string} symbolConfig.fillColor
 * @param {number} symbolConfig.fillOpacity
 * @param {string} symbolConfig.strokeColor
 * @param {number} symbolConfig.strokeWidth
 * @param {number} symbolConfig.strokeOpacity
 * @param {number} symbolConfig.padding
 * @param {number} symbolConfig.borderRadius
 * @param {number} symbolConfig.rotate - rotation in deg | turn | rad. ***default = 0***
 * @param {boolean} dontScale 
 * @returns {string} svg path in string format
 */

export function getHTML4SVGSymbol(symbolConfig, dontScale) {
    const { size = 1, width = symbolConfig.width || size, height = symbolConfig.height || size, shape, fillColor = 'black',
        fillOpacity = 1, strokeColor = 'black', strokeWidth = 1, strokeOpacity = 1, padding = 0, borderRadius = 0, rotate = 0,
        translateX = symbolConfig.translateX || (width / 2), translateY = symbolConfig.translateY || (height / 2) } = symbolConfig,
        size_w = dontScale ? mathMax(width - padding * 2, 1) : 10,
        size_h = dontScale ? mathMax(height - padding * 2, 1) : 10,
        _wF = mathMax(width - padding * 2, 1) / (size_w + 2 * validateNullVal(strokeWidth, 1)),
        _hF = mathMax(height - padding * 2, 1) / (size_h + 2 * validateNullVal(strokeWidth, 1)),
        symbolpath = getSVGsymbol(shape || 'square')(size_w, size_h, borderRadius),
        hexToRGB = legend_helpers.hexToRGB;

    return `<path d='${symbolpath}' transform='translate(${translateX},${translateY}) scale(${_wF},${_hF}) rotate(${rotate
        })' style='stroke: ${hexToRGB(strokeColor)}; fill: ${hexToRGB(fillColor)}; fill-opacity: ${fillOpacity
        }; stroke-width: ${validateNullVal(strokeWidth, 1)}px; stroke-opacity: ${strokeOpacity};'></path>`;
}

/**
 *
 * @param pathString
 * @param width
 * @param height
 * @param {boolean} notAsURL
 * @return {string}
 */

export function getSVGSymbolString(pathString, width, height, notAsURL) {
    var xml = `<svg xmlns='${'ht'+'tp'}://www.w3.org/2000/svg' xmlns:xlink='${'ht'+'tp'}://www.w3.org/1999/xlink' width='${width}' height='${height}'>`;
    xml += pathString;
    xml += ' </svg>';
    let url = `data:image/svg+xml;'}${$Browser.IE ? 'base64' : 'utf8'},${$Browser.IE ? btoa(xml) : xml}`;
    return notAsURL ? url : `url("${url}")`;
}
